#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <string.h>
#define INF 0x3f3f3f3f3f3f3f3fLL
#define MAXN 505
#define MAXM 505
#define MAXD 505

int N, M, D, R, C;
int wage[MAXN][MAXM];
int dist[MAXN][MAXM];
int dx[] = {-1, 0, 1, 0};
int dy[] = {0, -1, 0, 1};

void dijkstra() {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            dist[i][j] = INF;
        }
    }
    dist[R][C] = 0;
    int pq[MAXN * MAXM];
    int pq_size = 0;
    pq[pq_size++] = R * M + C;
    while (pq_size > 0) {
        int u = pq[0];
        for (int i = 1; i < pq_size; i++) {
            if (dist[u / M][u % M] > dist[pq[i] / M][pq[i] % M]) {
                u = pq[i];
            }
        }
        pq[0] = pq[pq_size - 1];
        pq_size--;
        for (int k = 0; k < 4; k++) {
            int x = u / M + dx[k];
            int y = u % M + dy[k];
            if (x >= 0 && x < N && y >= 0 && y < M && abs(x - R) + abs(y - C) <= D && (x*x + y*y < R*R + C*C)) {
                int v = x * M + y;
                if (dist[x][y] > dist[u / M][u % M] + wage[x][y]) {
                    dist[x][y] = dist[u / M][u % M] + wage[x][y];
                    pq[pq_size++] = v;
                }
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d %d %d", &N, &M, &D, &R, &C);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &wage[i][j]);
            }
        }
        dijkstra();
        if (dist[0][0] == INF) {
            printf("-1\n");
        } else {
            printf("%d\n", dist[0][0]);
        }
    }
    return 0;
}

