import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.PriorityQueue;
import java.util.StringTokenizer;

public class Main {
    static final int INF = 0x3f3f3f3f;
    static final int MAXN = 505;
    static final int MAXM = 505;
    static final int MAXD = 505;

    static int N, M, D, R, C;
    static int[][] wage = new int[MAXN][MAXM];
    static int[][] dist = new int[MAXN][MAXM];
    static int[] dx = {-1, 0, 1, 0};
    static int[] dy = {0, -1, 0, 1};

    static class Node implements Comparable<Node> {
        int x, y;
        int d;

        Node(int x, int y, int d) {
            this.x = x;
            this.y = y;
            this.d = d;
        }

        @Override
        public int compareTo(Node other) {
            return Integer.compare(d, other.d);
        }
    }

    static void dijkstra() {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dist[i][j] = INF;
            }
        }
        dist[R][C] = 0;
        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(R, C, 0));
        while (!pq.isEmpty()) {
            Node u = pq.poll();
            for (int k = 0; k < 4; k++) {
                int x = u.x + dx[k];
                int y = u.y + dy[k];
                if (x >= 0 && x < N && y >= 0 && y < M && Math.abs(x - R) + Math.abs(y - C) <= D && (x*x + y*y < R*R + C*C)) {
                    int v = x * M + y;
                    if (dist[x][y] > dist[u.x][u.y] + wage[x][y]) {
                        dist[x][y] = dist[u.x][u.y] + wage[x][y];
                        pq.add(new Node(x, y, dist[x][y]));
                    }
                }
            }
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            N = Integer.parseInt(st.nextToken());
            M = Integer.parseInt(st.nextToken());
            D = Integer.parseInt(st.nextToken());
            R = Integer.parseInt(st.nextToken());
            C = Integer.parseInt(st.nextToken());
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                for (int j = 0; j < M; j++) {
                    wage[i][j] = Integer.parseInt(st.nextToken());
                }
            }
            dijkstra();
            if (dist[0][0] == INF) {
                System.out.println(-1);
            } else {
                System.out.println(dist[0][0]);
            }
        }
    }
}

